// API Key authentication check - timing-safe comparison
const headers = $input.first().json.headers || {};

// Case-insensitive header lookup
const headerKeys = Object.keys(headers);
const apiKeyHeader = headerKeys.find(k => k.toLowerCase() === 'x-api-key');
const providedKey = apiKeyHeader !== undefined ? headers[apiKeyHeader] : $input.first().json.api_key;
const expectedKey = $env.LOCALAI_API_KEY;

// Timing-safe comparison - constant time regardless of input length
function timingSafeEqual(a, b) {
  if (typeof a !== 'string' || typeof b !== 'string') return false;
  const maxLen = Math.max(a.length, b.length);
  let result = 0;
  for (let i = 0; i < maxLen; i++) {
    const charA = i < a.length ? a.charCodeAt(i) : 0;
    const charB = i < b.length ? b.charCodeAt(i) : 0;
    result |= charA ^ charB;
  }
  return result === 0 && a.length === b.length;
}

if (expectedKey && !timingSafeEqual(providedKey || '', expectedKey)) {
  throw new Error('Authentication failed');
}

const input = $input.first().json || {};
const message = input.message || '';
const model = input.model || 'local-model';
const temperature = input.temperature;
const maxTokens = input.max_tokens;

// === MODEL VALIDATION ===
const validModelPattern = /^[a-zA-Z0-9._-]+$/;
if (!validModelPattern.test(model)) {
  throw new Error('Invalid model name: must be alphanumeric, dot, dash, or underscore only');
}
if (model.length > 100) {
  throw new Error('Model name too long: max 100 characters');
}

// === MESSAGE LENGTH VALIDATION ===
if (typeof message !== 'string') {
  throw new Error('Invalid message: must be a string');
}
if (message.length > 32768) {
  throw new Error('Message too long: max 32768 characters');
}
if (message.length === 0) {
  throw new Error('Missing required field: message');
}

// === TEMPERATURE VALIDATION ===
const tempValue = temperature !== undefined ? parseFloat(temperature) : 0.7;
if (isNaN(tempValue) || tempValue < 0.0 || tempValue > 2.0) {
  throw new Error('Invalid temperature: must be a number between 0.0 and 2.0');
}

// === MAX TOKENS VALIDATION ===
const tokensValue = maxTokens !== undefined ? parseInt(maxTokens, 10) : 1024;
if (isNaN(tokensValue) || tokensValue < 100 || tokensValue > 4096) {
  throw new Error('Invalid max_tokens: must be an integer between 100 and 4096');
}

// === CHANNEL VALIDATION ===
const channelRaw = (input.channel || 'general').replace(/^#+/, '').replace(/[<>@&]/g, '').slice(0, 100);
if (!channelRaw.match(/^[a-zA-Z0-9_-]+$/)) {
  throw new Error('Invalid channel: must be alphanumeric, dash, or underscore only');
}

return [{
  json: {
    message: message,
    model: model,
    temperature: tempValue,
    max_tokens: tokensValue,
    channel: channelRaw,
    stream: false
  }
}];

// Process LocalAI response
const body = $input.first().json || {};
const webhookInput = $input.all()[1]?.json || {};

const message = body.choices?.[0]?.message?.content || body.message?.content || 'No response generated';
const model = body.model || webhookInput.model || 'unknown';
const usage = body.usage || {};

return [{
  json: {
    success: !!message,
    model: model,
    response: message,
    tokens_used: usage.total_tokens || 0,
    prompt_tokens: usage.prompt_tokens || 0,
    completion_tokens: usage.completion_tokens || 0,
    timestamp: new Date().toISOString(),
    channel: webhookInput.channel || '#general'
  }
}];

